mapper.select:
SELECT w.id AS id, w.member_id AS memberId, w.balance_amount AS balanceAmount, w.total_recharge_amount AS totalRechargeAmount, w.total_consume_amount AS totalConsumeAmount, w.status AS status, DATE_FORMAT(w.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt, DATE_FORMAT(w.updated_at, '%Y-%m-%d %H:%i:%s') AS updatedAt, (select nickname from user_info where userId = w.member_id) AS memberName, (select phone from user_info where userId = w.member_id) AS memberMobile FROM pt_member_wallet w
ORDER BY w.updated_at DESC, w.id DESC
LIMIT #{offset}, #{limit}

SELECT f.id AS id, f.wallet_id AS walletId, f.member_id AS memberId, f.flow_type AS flowType, f.change_amount AS changeAmount, f.before_balance AS beforeBalance, f.after_balance AS afterBalance, f.biz_type AS bizType, f.biz_id AS bizId, f.remark AS remark, f.created_by AS createdBy, f.out_order_no AS outOrderNo, DATE_FORMAT(f.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt, (select nickname from user_info where userId = f.member_id) AS memberName, (select phone from user_info where userId = f.member_id) AS memberMobile FROM pt_member_wallet_flow f
ORDER BY f.id DESC
LIMIT #{offset}, #{limit}
